      <p class="mt-2 text-gray-600">Testez vos connaissances avec nos examens</p>
    </div>

    <!-- Filters -->
    <div class="mb-8 rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <div class="grid gap-4 md:grid-cols-3">
        <div>
          <label class="mb-2 block text-sm font-medium text-gray-700">Niveau</label>
          <select 
            [(ngModel)]="selectedLevelId"
            class="w-full rounded-lg border border-gray-300 px-3 py-2 focus:border-[#1A73E8] focus:outline-none focus:ring-2 focus:ring-[#1A73E8]/20">
            <option value="">Tous les niveaux</option>
            <option *ngFor="let level of levels()" [value]="level.id">{{ level.name }}</option>
          </select>
        </div>

        <div>
          <label class="mb-2 block text-sm font-medium text-gray-700">Matière</label>
          <select 
            [(ngModel)]="selectedSubjectId"
            class="w-full rounded-lg border border-gray-300 px-3 py-2 focus:border-[#1A73E8] focus:outline-none focus:ring-2 focus:ring-[#1A73E8]/20">
            <option value="">Toutes les matières</option>
            <option *ngFor="let subject of subjects()" [value]="subject.id">{{ subject.name }}</option>
          </select>
        </div>

        <div class="flex items-end">
          <button (click)="clearFilters()" class="w-full rounded-lg border border-gray-300 px-4 py-2 text-gray-700 hover:bg-gray-50">
            Réinitialiser
          </button>
        </div>
      </div>
    </div>

    <!-- Loading -->
    <div *ngIf="isLoading()" class="grid gap-6 md:grid-cols-2">
      <div *ngFor="let item of [1,2,3,4]" class="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="h-6 w-1/3 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-4 h-8 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-2 h-4 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-4 h-10 w-full animate-pulse rounded-xl bg-gray-200"></div>
      </div>
    </div>

    <!-- Exams Grid -->
    <div *ngIf="!isLoading()" class="grid gap-6 md:grid-cols-2">
      <div *ngFor="let exam of filteredExams()" class="rounded-xl border border-gray-200 bg-white p-6 shadow-sm transition hover:shadow-lg">
        <div class="mb-4 flex items-center justify-between">
          <span class="rounded-full bg-[#1A73E8]/10 px-3 py-1 text-sm font-medium text-[#1A73E8]">
            {{ exam.subjectName }}
          </span>
          <span class="rounded-full bg-gray-100 px-3 py-1 text-sm font-medium text-gray-600">
            {{ exam.levelName }}
          </span>
        </div>

        <h3 class="mb-2 text-xl font-semibold text-gray-900">{{ exam.title }}</h3>
        <p class="mb-4 text-gray-600">{{ exam.description }}</p>

        <div class="mb-4 grid grid-cols-2 gap-4 text-sm text-gray-600">
          <div><strong>Durée:</strong> {{ exam.duration }}min</div>
          <div><strong>Questions:</strong> {{ exam.questionCount }}</div>
          <div><strong>Note totale:</strong> {{ exam.totalMarks }}</div>
          <div><strong>Passage:</strong> {{ exam.passingMarks }}</div>
        </div>

        <div *ngIf="exam.scheduledAt" class="mb-4 text-sm text-gray-500">
          <strong>Date:</strong> {{ exam.scheduledAt | date:'dd/MM/yyyy' }}
        </div>

        <a [routerLink]="['/exams', exam.id]" class="block w-full rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] py-3 text-center text-sm font-semibold text-white">
          Commencer l'examen
        </a>
      </div>
    </div>

    <!-- Empty -->
    <div *ngIf="!isLoading() && filteredExams().length === 0" class="rounded-xl border border-dashed border-gray-300 bg-white p-10 text-center">
      <h3 class="text-lg font-semibold text-gray-900">Aucun examen trouvé</h3>
      <p class="mt-2 text-gray-600">Essayez de modifier les filtres</p>
      <button (click)="clearFilters()" class="mt-4 rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-4 py-2 text-sm font-semibold text-white">
        Réinitialiser les filtres
      </button>
    </div>
  </div>
</div>
